def generate_fto_analysis(claims, prior_art_docs):
    fto_recommendations = []

    for claim in claims:
        claim_info = predict_claim_info(claim['text'])

        # Generate claim chart
        claim_chart = generate_claim_chart(claim, prior_art_docs)

        # Determine licensing recommendation based on scope
        if claim_info['scope'] == 'narrow':
            recommendation = "Consider narrow claims for specific implementations."
        elif claim_info['scope'] == 'broad':
            recommendation = "Broad claims provide significant leverage in licensing negotiations."
        else:
            recommendation = "Moderate claims offer balanced coverage and enforceability."

        gaps = find_gaps_in_claim_chart(claim_chart)
        design_arounds = suggest_design_around(gaps)

        fto_recommendations.append({
            "claim_chart": claim_chart,
            "licensing_recommendation": recommendation,
            "design_arounds": design_arounds
        })

    return fto_recommendations

